\begin{equation}
\label{eq:dxdy_vector}
    \begin{pmatrix}
    \displaystyle
    dx \\ 
    dy 
    \end{pmatrix}
    =
    \begin{pmatrix}
    \displaystyle
        \frac{\pd x}{\pd u} & 
